import * as React from "react"

import "../styles/books.css"

import Header from "../components/header"
import Footer from "../components/footer"
import backgroundImage from "../images/background.jpg"
import irodori from "../images/irodori.png"
import koubou from "../images/koubou.png"





import { Container, Card } from "react-bootstrap";
import {FaBook} from "react-icons/fa"
import { SiPixiv } from "react-icons/si"


export default function books() {
    const books = [
        {
            title: "光芒",
            image: koubou,
            description: "発行 : コミックマーケット106\n\nミレニアムを卒業したユウカ。\n過去、彼女を悩ませていた「不眠症」の魔の手が、再び彼女を襲う。\n\n独り戦っていた彼女はある日、偶然 \"彼\" と再会する。",
            sample: "https://www.pixiv.net/novel/show.php?id=25524291",
            link : "https://www.melonbooks.co.jp/detail/detail.php?product_id=3198557"
        },
        {
            title: "過ぎ行く日々に彩を",
            image: irodori,
            description: "発行 : CC福岡62(青春の方舟3)\n\n3人の生徒と、それぞれドライブをするお話\n先生と生徒による、とある日々の一幕を体験していきませんか？\n\n収録内容\n・「消毒香る窓の中」/氷室セナ\n・「潮の息吹と砂の味」/旗見エリカ\n・「街明かりに照らされて」/錠前サオリ\n※コピ本なので通販ありません",
            sample: "https://www.pixiv.net/novel/show.php?id=25001320",
            link : null
        }
    ]
  return (
    <>
      <Header />

      <div
        className="bg-image"
        style={{
          backgroundImage: `url(${backgroundImage})`,
        }}
      />
      <Container className="py-5">
        <Card className="shadow-sm bg-light">
          <Card.Body> 
              <h4 className="text-start">既刊一覧</h4>
              <p className="text-start">
                同人サークル「ひらめの煮付け」として発行した同人誌の一覧です<br />
              </p>
          </Card.Body>
        </Card>
            {books.map((book) => {
              return (
                <Card className="mt-4 bg-light book-card">
                    <Card.Body>

                        {/* タイトル（固定） */}
                        <h4 className="mb-3">{book.title}</h4>

                        {/* ここだけ切り替え対象 */}
                        <div className="book-content">

                        <img
                            className="book-cover"
                            src={book.image}
                            alt={book.title}
                        />

                        <p className="book-desc mb-0" style={{ whiteSpace: "pre-line" }}>
                            {book.description}
                        </p>

                        </div>
                        {book.sample && (
                            <Card
                                key={book.sample}
                                as="a"
                                href={book.sample}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="mt-3 text-decoration-none link-card bg-light hover-shadow"
                            >
                                <Card.Body className="d-flex align-items-center">
                                    <SiPixiv size={24} className="me-3" />
                                    <span>サンプル(pixiv)</span>
                                </Card.Body>
                            </Card>
                        )}
                        {book.link && (
                            <Card
                                key={book.link}
                                as="a"
                                href={book.link}
                                target="_blank"
                                rel="noopener noreferrer"
                                className="mt-3 text-decoration-none link-card bg-light hover-shadow"
                            >
                                <Card.Body className="d-flex align-items-center">
                                    <FaBook size={24} className="me-3" />
                                    <span>実本通販（メロンブックス）</span>
                                </Card.Body>
                            </Card>/*
                            <div className="mt-3">
                                <a
                                href={book.link}
                                target="_blank"
                                rel="noopener noreferrer"
                                >
                                通販ページ
                                </a>
                            </div>*/
                        )}
                    </Card.Body>
                </Card>
              )
            })}
      </Container>
      <Footer />
    </>
  );
}